htmlContent:
{%- assign first_header = block_1_header_text | default: 'Build your emails faster' -%}
{%- assign first_body = block_1_paragraph_text | default: 'Start with a prebuilt content block, then customize the copy, image, and link.' -%}
{%- assign first_cta = block_1_cta_text | default: 'Browse templates' -%}
{%- assign second_header = block_2_header_text | default: 'Design every message with confidence' -%}
{%- assign second_body = block_2_paragraph_text | default: 'Pair each message with a clear CTA so readers know exactly where to go next.' -%}
{%- assign second_cta = block_2_cta_text | default: 'View best practices' -%}

<style>
  @media only screen and (max-width: 600px) {
    .two-column-content-block-column {
      display: block !important;
      width: 100% !important;
      max-width: 100% !important;
      padding-left: 0 !important;
      padding-right: 0 !important;
    }

    .two-column-content-block-spacer {
      display: block !important;
      height: 24px !important;
      line-height: 24px !important;
      font-size: 24px !important;
    }

    .two-column-content-block-image {
      width: 100% !important;
      max-width: 100% !important;
    }
  }
</style>

<table width="100%" border="0" cellpadding="0" cellspacing="0" role="presentation">
  <tbody>
    <tr>
      <td align="center" style="padding: 16px 0">
        <table width="100%" border="0" cellpadding="0" cellspacing="0" role="presentation" style="max-width: 600px">
          <tbody>
            <tr>
              <td class="two-column-content-block-column" valign="top" width="288" style="padding: 0">
                <table width="100%" border="0" cellpadding="0" cellspacing="0" role="presentation">
                  <tbody>
                    <tr>
                      <td>
                        <img
                          class="two-column-content-block-image"
                          src="{{ block_1_image.url }}"
                          alt="{{ block_1_image.alt | default: first_header }}"
                          width="288"
                          height="216"
                          style="display: block; width: 100%; max-width: 288px; height: 216px; object-fit: cover; border: 1px solid #d1d5db; border-radius: 10px; outline: none; text-decoration: none;"
                        />
                      </td>
                    </tr>
                    <tr>
                      <td style="padding: 16px 0 0 0">
                        <h2 style="margin: 0 0 8px 0; color: #111827; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif; font-size: 20px; line-height: 28px; font-weight: 700;">
                          {{ first_header }}
                        </h2>
                        <p style="margin: 0 0 8px 0; color: #4b5563; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif; font-size: 15px; line-height: 22px; font-weight: 400;">
                          {{ first_body }}
                        </p>
                        {% if block_1_cta_url and block_1_cta_url != "" %}
                        <a href="{{ block_1_cta_url }}" style="color: #000000; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif; font-size: 15px; line-height: 22px; font-weight: 600; text-decoration: underline;">
                          {{ first_cta }}
                        </a>
                        {% endif %}
                      </td>
                    </tr>
                  </tbody>
                </table>
              </td>
              <td class="two-column-content-block-spacer" width="24" style="font-size: 0; line-height: 0">&nbsp;</td>
              <td class="two-column-content-block-column" valign="top" width="288" style="padding: 0">
                <table width="100%" border="0" cellpadding="0" cellspacing="0" role="presentation">
                  <tbody>
                    <tr>
                      <td>
                        <img
                          class="two-column-content-block-image"
                          src="{{ block_2_image.url }}"
                          alt="{{ block_2_image.alt | default: second_header }}"
                          width="288"
                          height="216"
                          style="display: block; width: 100%; max-width: 288px; height: 216px; object-fit: cover; border: 1px solid #d1d5db; border-radius: 10px; outline: none; text-decoration: none;"
                        />
                      </td>
                    </tr>
                    <tr>
                      <td style="padding: 16px 0 0 0">
                        <h2 style="margin: 0 0 8px 0; color: #111827; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif; font-size: 20px; line-height: 28px; font-weight: 700;">
                          {{ second_header }}
                        </h2>
                        <p style="margin: 0 0 8px 0; color: #4b5563; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif; font-size: 15px; line-height: 22px; font-weight: 400;">
                          {{ second_body }}
                        </p>
                        {% if block_2_cta_url and block_2_cta_url != "" %}
                        <a href="{{ block_2_cta_url }}" style="color: #000000; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif; font-size: 15px; line-height: 22px; font-weight: 600; text-decoration: underline;">
                          {{ second_cta }}
                        </a>
                        {% endif %}
                      </td>
                    </tr>
                  </tbody>
                </table>
              </td>
            </tr>
          </tbody>
        </table>
      </td>
    </tr>
  </tbody>
</table>

{%- assign callout_header = header_text | default: 'TLDR' -%}
{%- assign callout_body = paragraph_text | default: 'Add a concise summary of the most important takeaway here.' -%}
{%- assign callout_background = '#fff7ed' -%}
{%- assign callout_border = '#fed7aa' -%}
{%- assign callout_heading = '#9a3412' -%}
{%- assign callout_text = '#7c2d12' -%}
{%- if color == 'blue' -%}
  {%- assign callout_background = '#eff6ff' -%}
  {%- assign callout_border = '#bfdbfe' -%}
  {%- assign callout_heading = '#1d4ed8' -%}
  {%- assign callout_text = '#1e3a8a' -%}
{%- elsif color == 'green' -%}
  {%- assign callout_background = '#f0fdf4' -%}
  {%- assign callout_border = '#bbf7d0' -%}
  {%- assign callout_heading = '#15803d' -%}
  {%- assign callout_text = '#14532d' -%}
{%- elsif color == 'purple' -%}
  {%- assign callout_background = '#faf5ff' -%}
  {%- assign callout_border = '#e9d5ff' -%}
  {%- assign callout_heading = '#7e22ce' -%}
  {%- assign callout_text = '#581c87' -%}
{%- elsif color == 'gray' -%}
  {%- assign callout_background = '#f8fafc' -%}
  {%- assign callout_border = '#e2e8f0' -%}
  {%- assign callout_heading = '#334155' -%}
  {%- assign callout_text = '#475569' -%}
{%- endif -%}

<table width="100%" border="0" cellpadding="0" cellspacing="0" role="presentation">
  <tbody>
    <tr>
      <td style="padding: 16px 0">
        <table width="100%" border="0" cellpadding="0" cellspacing="0" role="presentation" style="background-color: {{ callout_background }}; border: 1px solid {{ callout_border }}; border-collapse: separate; border-radius: 12px; border-spacing: 0; overflow: hidden;">
          <tbody>
            <tr>
              <td style="background-color: {{ callout_background }}; border-radius: 12px; padding: 20px 24px;">
                <h1 style="margin: 0 0 8px 0; color: {{ callout_heading }}; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif; font-size: 24px; line-height: 32px; font-weight: 700;">
                  {{ callout_header }}
                </h1>
                <p style="margin: 0; color: {{ callout_text }}; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif; font-size: 16px; line-height: 24px; font-weight: 400;">
                  {{ callout_body }}
                </p>
              </td>
            </tr>
          </tbody>
        </table>
      </td>
    </tr>
  </tbody>
</table>

{%- assign destination_url = cover_image.action | default: optional_link -%}
<style>
  @media only screen and (max-width: 480px) {
    .video-cover-play-circle {
      width: 54px !important;
      height: 54px !important;
    }
    .video-cover-play-triangle {
      border-top-width: 8px !important;
      border-bottom-width: 8px !important;
      border-left-width: 13px !important;
    }
  }
</style>

<table width="100%" border="0" cellpadding="0" cellspacing="0" role="presentation">
  <tr>
    <td align="center" style="padding: 0">
      <div style="max-width: 640px; margin: 0 auto; position: relative; line-height: 0; font-size: 0">
        {% if destination_url and destination_url != "" %}
        <a
          href="{{ destination_url }}"
          style="text-decoration: none; display: block; position: relative"
        >
        {% endif %}
          <img
            src="{{ cover_image.url }}"
            alt="{{ cover_image.alt | default: 'Video cover image' }}"
            width="640"
            style="
              display: block;
              width: 100%;
              max-width: 640px;
              height: auto;
              border: 0;
              border-radius: 8px;
              outline: none;
              text-decoration: none;
            "
          />
          <div
            style="
              position: absolute;
              left: 50%;
              top: 50%;
              transform: translate(-50%, -50%);
              -webkit-transform: translate(-50%, -50%);
              mso-hide: all;
            "
          >
            <div
              class="video-cover-play-circle"
              style="
                width: 72px;
                height: 72px;
                border-radius: 36px;
                background-color: rgba(0, 0, 0, 0.72);
                display: table;
              "
            >
              <div
                style="
                  display: table-cell;
                  vertical-align: middle;
                  text-align: center;
                  line-height: 0;
                "
              >
                <span
                  class="video-cover-play-triangle"
                  style="
                    display: inline-block;
                    width: 0;
                    height: 0;
                    border-top: 11px solid transparent;
                    border-bottom: 11px solid transparent;
                    border-left: 18px solid #ffffff;
                    margin-left: 4px;
                  "
                ></span>
              </div>
            </div>
          </div>
        {% if destination_url and destination_url != "" %}
        </a>
        {% endif %}
      </div>
    </td>
  </tr>
</table>
